import{_ as t,c as s,o as i,ag as a}from"./chunks/framework.CSeR4K32.js";const n="/assets/pve_kvm_1.BEDy-Dxt.png",r="/assets/pve_kvm_2.C98l0GO8.png",o="/assets/pve_kvm_3.DzuyyWMo.png",k=JSON.parse('{"title":"Preface","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/en/guide/pve/pve_precheck.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"OneClickVirt"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Preface"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/en/guide/pve/pve_precheck.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Preface"}]]},"headers":[],"relativePath":"en/guide/pve/pve_precheck.md","filePath":"en/guide/pve/pve_precheck.md","lastUpdated":1782113927000}'),l={name:"en/guide/pve/pve_precheck.md"};function p(h,e,c,d,u,m){return i(),s("div",null,e[0]||(e[0]=[a(`<h1 id="preface" tabindex="-1">Preface <a class="header-anchor" href="#preface" aria-label="Permalink to &quot;Preface&quot;">​</a></h1><p>This page describes the standard (non-customized) workflow. Custom workflows are documented separately.</p><p>If your provider or machine is not yet supported, contact <a href="https://t.me/spiritlhl_bot" target="_blank" rel="noreferrer">@spiritlhl_bot</a>; support may be added in a future update.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>This process modifies host networking. Ensure the host can be reinstalled/recovered at any time and avoid running on hosts with critical data.</p></div><p>Feel free to give the project a <code>Star</code> for free support!--&gt;<a href="https://github.com/oneclickvirt/pve" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/pve</a></p><h2 id="various-requirements" tabindex="-1">Various requirements <a class="header-anchor" href="#various-requirements" aria-label="Permalink to &quot;Various requirements&quot;">​</a></h2><p>Use the latest stable Debian release whenever possible.</p><p><strong>Warning: This project only supports servers with a dedicated public IPv4 address</strong></p><p>This project relies on a fixed IPv4 address for network allocation and does not support the following scenarios:</p><ul><li>Environments with dynamic IPv4 (e.g., servers whose IP address changes after reboot)</li><li>Environments without a dedicated public IPv4 address (e.g., accessing the internet via home router NAT and requiring DHCP to obtain an address)</li></ul><p>If your server does not have a publicly routable static IPv4 address, please do not use this project.</p><p>The one-click installation script currently targets Debian systems only. Non-Debian systems are not supported through the APT workflow in this project. For other systems, use ISO installation or the manual/custom methods described in the FAQ section.</p><ul><li>System requirements: Debian 8+</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Debian 11 was historically the most conservative choice for this workflow. If your environment supports it, newer stable Debian releases can also be used.</p></div><ul><li>Hardware requirements: &gt;= 2 CPU cores, &gt;= 2 GB RAM, &gt;= 20 GB disk on <code>x86_64</code> or <code>arm</code> architecture</li><li>Hardware requirements for KVM: VM-X or AMD-V support (some VPS and all Dedicated servers support).</li><li>If hardware or system requirements are not met, you can use <code>incus</code> to batch open LXC containers <a href="https://github.com/oneclickvirt/incus" target="_blank" rel="noreferrer">Jump</a></li></ul><p>If you use IPv6 tunnels for IPv6 subnet attachment on the host, be sure to add the contents in the corresponding file when PVE is successfully installed but the gateway is not automatically set, and do not add IPv6 tunnels at the very beginning (without installing PVE).</p><p><strong>Warning: If your dedicated server has no IPMI or other remote rescue channel, and you cannot reinstall the system yourself, do not use this script. Ask your provider/technician to perform a manual ISO installation of PVE. Otherwise, you may lose connectivity on hosts that do not support safe hot network changes.</strong></p><h2 id="setting-up-virtual-memory-swap-optional-not-required" tabindex="-1">Setting up virtual memory (SWAP) (optional, not required) <a class="header-anchor" href="#setting-up-virtual-memory-swap-optional-not-required" aria-label="Permalink to &quot;Setting up virtual memory (SWAP) (optional, not required)&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If your host has limited memory and enough free disk, adding swap can reduce OOM risk.</p></div><p>Unit conversion: Enter 1024 to generate 1G SWAP-virtual memory, virtual memory occupies hard disk space.</p><p>When the actual memory is not enough, the virtual memory will be automatically used for memory usage, but it will bring high IO usage and CPU performance.</p><p>For swap sizing reference, see <a href="https://github.com/oneclickvirt/ecs/blob/master/README_NEW_USER.md" target="_blank" rel="noreferrer">this guide</a>.</p><table tabindex="0"><thead><tr><th>Physical Memory Size</th><th>Recommended SWAP Size</th></tr></thead><tbody><tr><td>≤ 2G</td><td>2x memory size</td></tr><tr><td>2G &lt; memory ≤ 8G</td><td>Equal to physical memory</td></tr><tr><td>≥ 8G</td><td>About 8G is sufficient</td></tr><tr><td>Hibernation needed</td><td>At least equal to physical memory</td></tr></tbody></table><p>The above values are only recommended settings, the actual value according to their own needs, do not blindly copy the value!</p><p>Command:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/spiritLHLS/addswap/main/addswap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="detecting-the-environment" tabindex="-1">Detecting the environment <a class="header-anchor" href="#detecting-the-environment" aria-label="Permalink to &quot;Detecting the environment&quot;">​</a></h2><ul><li>This pre-check must be run before other related scripts. If prerequisites are not met, later PVE scripts may fail.</li><li>Detects local IPv6 network status (informational; install itself does not require IPv6)</li><li>Verifies whether hardware meets minimum requirements</li><li>Detects whether the hardware supports nested KVM virtualization. If KVM is unavailable, VMs can still run with QEMU TCG emulation, but performance will be poor.</li><li>Detects whether the current system environment is suitable for nested KVM usage.</li><li>If nested KVM is unavailable, PVE is usually not recommended; <a href="https://github.com/oneclickvirt/incus" target="_blank" rel="noreferrer">incus</a> is often a better fit for performance and stability.</li></ul><p>Command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSLk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/oneclickvirt/pve/main/scripts/check_kernal.sh)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you need to update the IPv6 information before querying, then execute the following command before querying</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/pve_ipv6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/pve_check_ipv6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/pve_last_ipv6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Commands to set up the testing environment for executing this project are as follows:</strong></p><p><img src="`+n+'" alt="图片" loading="lazy"></p><p>To perform the above-mentioned query, you only need to use the one-click script below to automatically create a virtual machine. There is no need to manually modify settings on the web interface.</p><p><img src="'+r+'" alt="图片" loading="lazy"></p><p>After creating the virtual machines using the subsequent script as mentioned above, it <strong>may</strong> be necessary to manually modify the settings on the web interface. You will need to disable hardware nested virtualization for each respective virtual machine, as shown in the following diagram.</p><p><img src="'+o+'" alt="图片" loading="lazy"></p><p>Stop the virtual machine before making modifications. After the modifications are done, you can start the machine to use NOVNC. Failure to close it <strong>may</strong> result in bugs that render this virtual machine unusable.</p><p>If you forcibly install PVE to enable KVM, even if the startup fails, you can also disable this option and try to start the virtual machine to see if it works.</p><p>The reason for these issues is what was stated above, the host does not support nested virtualized KVMs for acceleration.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Please use the &quot;screen&quot; command to suspend execution before launching the virtual machine, in order to avoid prolonged startup times. Unstable SSH connections could lead to interruptions during the intermediate execution.</p></div><br><br>',44)]))}const b=t(l,[["render",p]]);export{k as __pageData,b as default};
